app.post('/authorize/consent', (req, res) => {
  if (!req.session.user || !req.session.authRequest) {
    return res.status(400).send('Invalid request');
  }

  const { consent } = req.body;
  const { client_id, redirect_uri, state, scope } = req.session.authRequest;

  if (consent !== 'approve') {
    const errorUrl = `${redirect_uri}?error=access_denied&state=${state || ''}`;
    req.session.authRequest = null;
    return res.redirect(errorUrl);
  }

  const authCode = generateRandomString(32);
  authorizationCodes.set(authCode, {
    client_id,
    redirect_uri,
    username: req.session.user.username,
    email: req.session.user.email,
    scope,
    expiresAt: Date.now() + 600000,
    used: false
  });

  req.session.authRequest = null;

  const callbackUrl = `${redirect_uri}?code=${authCode}${state ? '&state=' + state : ''}`;
  res.redirect(callbackUrl);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!code || !redirect_uri || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
  }

  const client = registeredClients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const authCodeData = authorizationCodes.get(code);
  if (!authCodeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  }

  if (authCodeData.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code already used' });
  }

  if (authCodeData.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (authCodeData.client_id !== client_id) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client ID mismatch' });
  }

  if (authCodeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  authCodeData.used = true;

  const accessToken = generateRandomString(64);
  const refreshToken = generateRandomString(64);

  accessTokens.set(accessToken, {
    client_id,
    username: authCodeData.username,
    email: authCodeData.email,
    scope: authCodeData.scope,
    expiresAt: Date.now() + 3600000
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authCodeData.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token expired' });
  }

  res.json({
    sub: tokenData.username,
    email: tokenData.email,
    email_verified: true
  });
});

